   getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
     const opts = { ...(opOptions?.options || {}) };
     return opts;
   }
+
+  private getCursorSort(orderBy?: CrudOptions<T>['orderBy']) {
+    if (!orderBy) {
+      return [] as { field: string; direction: 'asc' | 'desc' }[];
+    }
+
+    const orderByItems = Array.isArray(orderBy) ? orderBy : [orderBy];
+    const sort = [] as { field: string; direction: 'asc' | 'desc' }[];
+    for (const item of orderByItems) {
+      for (const [field, value] of Object.entries(item || {})) {
+        const direction = String(value).toLowerCase();
+        if (direction !== 'asc' && direction !== 'desc') {
+          throw new BadRequestException(
+            'Cursor pagination only supports asc and desc order directions',
+          );
+        }
+        sort.push({ field, direction });
+      }
+    }
+
+    const idField = this.crudConfig.id_field;
+    if (!sort.some((item) => item.field === idField)) {
+      sort.push({ field: idField, direction: 'asc' });
+    }
+    return sort;
+  }
+
+  private parseCursor(
+    encodedCursor: string | undefined,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+    offset: number | undefined,
+  ): Record<string, any> | undefined {
+    if (!encodedCursor) {
+      return undefined;
+    }
+    if (!sort.length) {
+      throw new BadRequestException('Cursor requires orderBy');
+    }
+    if (offset !== undefined) {
+      throw new BadRequestException('Cursor cannot be used with offset');
+    }
+
+    let cursor: Record<string, any>;
+    try {
+      if (
+        !/^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/.test(
+          encodedCursor,
+        )
+      ) {
+        throw new Error('Invalid Base64');
+      }
+      const value = Buffer.from(encodedCursor, 'base64').toString('utf8');
+      cursor = JSON.parse(value);
+      if (!cursor || Array.isArray(cursor) || typeof cursor !== 'object') {
+        throw new Error('Invalid cursor payload');
+      }
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    const expectedSort = this.getCursorSortString(sort);
+    if (cursor.__sort !== expectedSort) {
+      throw new BadRequestException('Cursor sort does not match orderBy');
+    }
+    for (const { field } of sort) {
+      if (!Object.prototype.hasOwnProperty.call(cursor, field)) {
+        throw new BadRequestException(`Cursor is missing ${field}`);
+      }
+    }
+    return cursor;
+  }
+
+  private applyCursor(
+    entity: Partial<T>,
+    cursor: Record<string, any>,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const afterCursor = sort.map(({ field, direction }, index) => {
+      const condition: Record<string, any> = {};
+      for (const previous of sort.slice(0, index)) {
+        condition[previous.field] = cursor[previous.field];
+      }
+      condition[field] = {
+        [direction === 'asc' ? '$gt' : '$lt']: cursor[field],
+      };
+      return condition;
+    });
+    return { $and: [entity, { $or: afterCursor }] } as Partial<T>;
+  }
+
+  private getCursorOrderBy(sort: { field: string; direction: 'asc' | 'desc' }[]) {
+    return sort.map(({ field, direction }) => ({ [field]: direction }));
+  }
+
+  private getCursorSortString(
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    return sort.map(({ field, direction }) => `${field}:${direction}`).join(',');
+  }
+
+  private createCursor(
+    entity: T,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const cursor: Record<string, any> = {
+      __sort: this.getCursorSortString(sort),
+    };
+    for (const { field } of sort) {
+      cursor[field] = entity[field];
+    }
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
